const b = $input.first().json.body || $input.first().json;
if (!b.period_year || !b.period_month) throw new Error('period_year y period_month son requeridos');
return [{ json: {
  clinic_id:    b.clinic_id ? Number(b.clinic_id) : 1,
  period_year:  Number(b.period_year),
  period_month: Number(b.period_month),
  notes:        b.notes || '',
  created_by:   b.created_by || ''
} }];

const b = $input.first().json.body || $input.first().json;
if (!b.id) throw new Error('id del período es requerido');
return [{ json: { period_id: b.id, calculated_by: b.calculated_by || '' } }];

// Gather all data from previous nodes
const periodRow  = $('Fetch Period + Settings').first().json;
const contracts  = $('Fetch Active Contracts').all().map(i => i.json);
const sessionsMap = {};
for (const s of $('Fetch Sessions Revenue').all()) {
  sessionsMap[s.json.doctor_id] = s.json;
}

// Parse settings
const settings = periodRow.settings || {};
const bpsEmployeeRate  = Number(settings.bps_employee_rate  ?? 0.15);
const fonasaBasicRate  = Number(settings.fonasa_employee_base ?? 0.03);
const fonasaChildRate  = Number(settings.fonasa_employee_children ?? 0.06);
const bpsEmployerRate  = Number(settings.bps_employer_rate   ?? 0.075);
const fonasaEmpRate    = Number(settings.fonasa_employer_rate ?? 0.05);
const frlEmployeeRate  = Number(settings.frl_employee_rate   ?? 0.00125);
const frlEmployerRate  = Number(settings.frl_employer_rate   ?? 0.001);
const fgclRate         = Number(settings.fgcl_rate           ?? 0.00025);
bseRate                = Number(settings.bse_rate            ?? 0.003);
const bpsCap           = Number(settings.bps_salary_cap_uyu  ?? 272564);
const bpcValue         = Number(settings.bpc_value_uyu       ?? 6600);
const vacDays          = Number(settings.vacation_days_per_year ?? 20);
const irpfBrackets     = settings.irpf_brackets ?? [
  {from:0,   to:84,   rate:0},
  {from:84,  to:120,  rate:0.10},
  {from:120, to:180,  rate:0.15},
  {from:180, to:600,  rate:0.24},
  {from:600, to:900,  rate:0.25},
  {from:900, to:1320, rate:0.27},
  {from:1320,to:2400, rate:0.31},
  {from:2400,to:null, rate:0.36}
];

function calcIRPF(grossMonthly, bpcVal, brackets, totalAportesEmployee) {
  const grossAnnual = grossMonthly * 12;
  const grossBPC = grossAnnual / bpcVal;
  let irpfAnnual = 0;
  let remaining = grossBPC;
  for (const b of brackets) {
    if (remaining <= 0) break;
    const width = b.to === null ? remaining : Math.min(b.to - b.from, remaining);
    irpfAnnual += width * bpcVal * b.rate;
    remaining -= (b.to === null ? remaining : width);
  }
  // Standard deduction: employee BPS/FONASA contributions reduce IRPF base
  const annualAportes = totalAportesEmployee * 12;
  const deduction = annualAportes * 0.06;
  irpfAnnual = Math.max(0, irpfAnnual - deduction);
  return Math.round((irpfAnnual / 12) * 100) / 100;
}

const entries = [];

for (const contract of contracts) {
  const sess = sessionsMap[contract.doctor_id] || {
    sessions_count: 0, hours_worked: 0, revenue_listed: 0, revenue_billed: 0
  };

  const sessionsCount    = Number(sess.sessions_count) || 0;
  const hoursWorked      = Number(sess.hours_worked)   || 0;
  const revenueListed    = Number(sess.revenue_listed)  || 0;
  const revenueBilled    = Number(sess.revenue_billed)  || 0;

  // Base calculation
  let baseAmount     = 0;
  let variableAmount = 0;
  const calcType     = contract.calculation_type;
  const basis        = contract.percentage_basis;
  const revenueBase  = basis === 'sobre_cobrado' ? revenueBilled : revenueListed;

  if (calcType === 'fijo') {
    baseAmount = Number(contract.base_salary) || 0;
  } else if (calcType === 'por_hora') {
    baseAmount = (Number(contract.hourly_rate) || 0) * hoursWorked;
  } else if (calcType === 'porcentaje') {
    variableAmount = revenueBase * (Number(contract.percentage_rate) || 0) / 100;
  } else if (calcType === 'fijo_porcentaje') {
    baseAmount = Number(contract.base_salary) || 0;
    const threshold = Number(contract.percentage_threshold) || 0;
    variableAmount = Math.max(0, revenueBase - threshold) * (Number(contract.percentage_rate) || 0) / 100;
  } else if (calcType === 'por_prestacion') {
    variableAmount = (Number(contract.per_session_rate) || 0) * sessionsCount;
  }

  const grossSalary = Math.round((baseAmount + variableAmount) * 100) / 100;

  // Deducciones solo para empleado en dependencia
  let bpsEmployee = 0, fonasaEmployee = 0, irpfWithholding = 0;
  let bpsEmployer = 0, fonasaEmployer = 0;
  let aguinaldoProv = 0, vacationProv = 0;

  const isEmpleado = ['empleado', 'mixto'].includes(contract.contract_type);

  if (isEmpleado) {
    const capBase = Math.min(grossSalary, bpsCap);
    bpsEmployee   = Math.round(capBase * bpsEmployeeRate * 100) / 100;
    const frlEmp  = Math.round(capBase * frlEmployeeRate * 100) / 100;
    // FONASA rate depends on family situation (stored in payroll_employees.fonasa_situation)
    // Default to basic rate here; will be refined once we fetch employee data
    fonasaEmployee = Math.round(capBase * fonasaBasicRate * 100) / 100;
    const totalAportes = bpsEmployee + fonasaEmployee + frlEmp;
    irpfWithholding = calcIRPF(grossSalary, bpcValue, irpfBrackets, totalAportes);

    bpsEmployer    = Math.round(capBase * bpsEmployerRate * 100) / 100;
    fonasaEmployer = Math.round(capBase * fonasaEmpRate * 100) / 100;
    const fgcl     = Math.round(capBase * fgclRate * 100) / 100;
    const bse      = Math.round(capBase * bseRate * 100) / 100;

    aguinaldoProv = Math.round((grossSalary / 12) * 100) / 100;
    vacationProv  = Math.round((grossSalary / 30) * (vacDays / 12) * 100) / 100;
  }

  const totalDeductions   = Math.round((bpsEmployee + fonasaEmployee + irpfWithholding) * 100) / 100;
  const netSalary         = Math.round((grossSalary - totalDeductions) * 100) / 100;
  const totalEmployerCost = Math.round((grossSalary + bpsEmployer + fonasaEmployer + aguinaldoProv + vacationProv) * 100) / 100;

  entries.push({
    period_id:              periodRow.period_id,
    doctor_id:              contract.doctor_id,
    contract_id:            contract.id,
    clinic_id:              periodRow.clinic_id,
    sessions_count:         sessionsCount,
    hours_worked:           hoursWorked,
    services_revenue_billed: revenueBilled,
    services_revenue_listed: revenueListed,
    base_amount:             baseAmount,
    variable_amount:         variableAmount,
    gross_salary:            grossSalary,
    bps_employee:            bpsEmployee,
    fonasa_employee:         fonasaEmployee,
    irpf_withholding:        irpfWithholding,
    other_deductions:        0,
    total_deductions:        totalDeductions,
    net_salary:              netSalary,
    bps_employer:            bpsEmployer,
    fonasa_employer:         fonasaEmployer,
    aguinaldo_provision:     aguinaldoProv,
    vacation_provision:      vacationProv,
    total_employer_cost:     totalEmployerCost,
    currency:                contract.currency || 'UYU',
    calculated_by:           $('Parse Calculate Request').first().json.calculated_by || ''
  });
}

return entries.map(e => ({ json: e }));

const period = $('Update Period Calculated').first().json;
const entries = $('Save Payroll Entry').all().map(i => i.json);
const totalGross = entries.reduce((s,e) => s + Number(e.gross_salary||0), 0);
const totalNet   = entries.reduce((s,e) => s + Number(e.net_salary||0), 0);
return [{ json: {
  period_id:     period.id,
  status:        period.status,
  generated_at:  period.generated_at,
  entries_count: entries.length,
  total_gross:   Math.round(totalGross * 100) / 100,
  total_net:     Math.round(totalNet   * 100) / 100
} }];
